  const segmentRefs = useRef({});
  const [indicatorStyle, setIndicatorStyle] = useState({});

  const updateIndicatorStyle = useCallback(() => {
    if (!selectedValue || !segmentRefs.current[selectedValue]) {
      // Handle cases where selectedValue might be null or not found (e.g., empty segments)
      setIndicatorStyle({}); // Hide or reset indicator
      return;
    }
    const activeSegmentRef = segmentRefs.current[selectedValue];
    setIndicatorStyle({
      width: activeSegmentRef.offsetWidth,
      transform: `translateX(${activeSegmentRef.offsetLeft}px)`,
    });
  }, [selectedValue]);

  // Effect for initial setup and when selectedValue or segments change
  useEffect(() => {
    updateIndicatorStyle();
  }, [selectedValue, segments, updateIndicatorStyle]);

  // Effect for window resize listener
  useEffect(() => {
    window.addEventListener('resize', updateIndicatorStyle);
    return () => {
      window.removeEventListener('resize', updateIndicatorStyle);
    };
  }, [updateIndicatorStyle]);

  const handleSegmentClick = (value) => {
    setSelectedValue(value);
    onChange && onChange(value);
