export class AppComponent implements AfterViewInit {
  segments: Segment[] = [
    { label: 'Daily', value: 'daily' },
    { label: 'Weekly', value: 'weekly' },
    { label: 'Monthly', value: 'monthly' },
  ];
  selected = 'weekly';
  indicatorWidth = 0;
  indicatorLeft = 0;

  @ViewChildren('segBtn') segBtns!: QueryList<ElementRef<HTMLButtonElement>>;

  ngAfterViewInit(): void {
    setTimeout(() => this.updateIndicator(), 0);
  }

  @HostListener('window:resize')
  onResize(): void {
    this.updateIndicator();
  }

  isActive(value: string): boolean {
    return this.selected === value;
  }

  select(value: string): void {
    this.selected = value;
    this.updateIndicator();
  }

  updateIndicator(): void {
    const buttons = this.segBtns.toArray();
    for (let i = 0; i < this.segments.length; i++) {
      if (this.segments[i].value === this.selected && buttons[i]) {
        const el = buttons[i].nativeElement;
        this.indicatorWidth = el.offsetWidth;
        this.indicatorLeft = el.offsetLeft;
        return;
      }
    }
  }
}

@NgModule({
  declarations: [AppComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
